      intervalWeeks: integer("interval_weeks"),
      // الفترة بالأسابيع
      intervalMonths: integer("interval_months"),
      // الفترة بالشهور
      // إعدادات الجدولة بالاستخدام
      usageHoursInterval: decimal("usage_hours_interval", { precision: 15, scale: 2 }),
