privateRouter.post("/download-file", async (req, res) => {
  try {
    const { base64, fileName, mimeType } = req.body;
    if (!base64 || !fileName || !mimeType) {
      return res.status(400).json({
        success: false,
        error: "\u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u0627\u0644\u0645\u0637\u0644\u0648\u0628\u0629 \u063A\u064A\u0631 \u0645\u0643\u062A\u0645\u0644\u0629"
      });
    }
    const buffer = Buffer.from(base64, "base64");
    const safeFileName = fileName.replace(/[^a-zA-Z0-9\u0600-\u06FF._-]/g, "_");
    res.set({
      "Content-Type": mimeType,
      "Content-Disposition": `attachment; filename*=UTF-8''${encodeURIComponent(safeFileName)}`,
      "Content-Length": buffer.length.toString(),
      "Cache-Control": "no-cache, no-store, must-revalidate",
      "Pragma": "no-cache",
      "Expires": "0"
    });
    res.send(buffer);
    console.log(`\u{1F4E5} [Download] \u062A\u0645 \u062A\u0646\u0632\u064A\u0644 \u0645\u0644\u0641: ${safeFileName} (${buffer.length} bytes)`);
  } catch (error) {
    console.error("\u274C [Download] \u062E\u0637\u0623 \u0641\u064A \u062A\u0646\u0632\u064A\u0644 \u0627\u0644\u0645\u0644\u0641:", error);
    res.status(500).json({
      success: false,
      error: "\u062E\u0637\u0623 \u0641\u064A \u062A\u0646\u0632\u064A\u0644 \u0627\u0644\u0645\u0644\u0641",
      code: "DOWNLOAD_ERROR"
    });
  }
});
