            totalExpenses: 0,
            totalExpensesAll: 0,
            totalIncome: 0,
            currentBalance: 0,
            totalBalance: 0,
            activeWorkers: 0,
            completedDays: 0,
            materialPurchases: 0,
            materialExpensesCredit: 0,
            lastActivity: project.createdAt.toISOString()
