var projectTypeRouter = express7.Router();
var requireRoles = (roles) => {
  return (req, res, next) => {
    const user = req.user;
    if (!user) {
      return res.status(401).json({
        success: false,
        message: "\u063A\u064A\u0631 \u0645\u0635\u0631\u062D \u0644\u0643 \u0628\u0627\u0644\u0648\u0635\u0648\u0644",
        code: "UNAUTHORIZED"
      });
    }
    if (!roles.includes(user.role)) {
      console.log(`\u{1F6AB} [AUTH] \u0645\u062D\u0627\u0648\u0644\u0629 \u0648\u0635\u0648\u0644 \u063A\u064A\u0631 \u0645\u0635\u0631\u062D \u0628\u0647\u0627 \u0645\u0646: ${user.email} \u0644\u0644\u0623\u062F\u0648\u0627\u0631: ${roles.join(", ")}`);
      return res.status(403).json({
        success: false,
        message: `\u062A\u062D\u062A\u0627\u062C \u0635\u0644\u0627\u062D\u064A\u0627\u062A ${roles.join(" \u0623\u0648 ")} \u0644\u0644\u0648\u0635\u0648\u0644 \u0644\u0647\u0630\u0627 \u0627\u0644\u0645\u062D\u062A\u0648\u0649`,
        code: "ROLE_REQUIRED"
      });
    }
    next();
  };
};
