function initializeBackupDir() {
  if (!existsSync4(BACKUP_DIR)) {
    mkdirSync3(BACKUP_DIR, { recursive: true });
    console.log(`\u{1F4C1} [AutoBackup] \u062A\u0645 \u0625\u0646\u0634\u0627\u0621 \u0645\u062C\u0644\u062F \u0627\u0644\u0646\u0633\u062E \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A\u0629: ${BACKUP_DIR}`);
  }
}
async function getAllTables() {
  try {
    const result = await db.execute(sql22`
      SELECT table_name 
      FROM information_schema.tables 
      WHERE table_schema = 'public' 
      AND table_type = 'BASE TABLE'
      ORDER BY table_name
    `);
    return result.rows.map((row) => row.table_name);
  } catch (error) {
    console.error("\u274C [AutoBackup] \u0641\u0634\u0644 \u062C\u0644\u0628 \u0642\u0627\u0626\u0645\u0629 \u0627\u0644\u062C\u062F\u0627\u0648\u0644:", error);
    return [];
  }
}
async function dumpAllTables() {
  const tables = await getAllTables();
  const dumpedTables = [];
  let totalRows = 0;
  for (const tableName of tables) {
    try {
      const columnsResult = await db.execute(sql22`
        SELECT column_name, data_type, is_nullable, column_default
        FROM information_schema.columns
        WHERE table_schema = 'public'
        AND table_name = ${tableName}
        ORDER BY ordinal_position
      `);
      const dataResult = await db.execute(sql22.raw(`SELECT * FROM "${tableName}"`));
      const columns = columnsResult.rows.map((row) => ({
        name: row.column_name,
        type: row.data_type,
        nullable: row.is_nullable === "YES",
        default: row.column_default
      }));
      dumpedTables.push({
        name: tableName,
        columns,
        data: dataResult.rows,
        rowCount: dataResult.rows.length
      });
      totalRows += dataResult.rows.length;
    } catch (error) {
      console.warn(`   \u26A0\uFE0F [AutoBackup] \u062A\u0639\u0630\u0631 \u0646\u0633\u062E \u062C\u062F\u0648\u0644 ${tableName}`);
      dumpedTables.push({
        name: tableName,
        columns: [],
        data: [],
        rowCount: 0
      });
    }
  }
  return {
    timestamp: (/* @__PURE__ */ new Date()).toISOString(),
    tables: dumpedTables,
    totalRows
  };
}
async function createFullBackup() {
  const startTime = Date.now();
  const dateTime = (/* @__PURE__ */ new Date()).toISOString().replace(/[:.]/g, "-").slice(0, -5);
  const backupFile = join4(BACKUP_DIR, `full_backup_${dateTime}.json`);
  try {
    console.log("\u{1F4BE} [AutoBackup] \u0628\u062F\u0621 \u0625\u0646\u0634\u0627\u0621 \u0646\u0633\u062E\u0629 \u0627\u062D\u062A\u064A\u0627\u0637\u064A\u0629 \u0643\u0627\u0645\u0644\u0629...");
    const dumpData = await dumpAllTables();
    const content = JSON.stringify(dumpData, null, 2);
    const size = Buffer.byteLength(content, "utf-8");
    writeFileSync3(backupFile, content, "utf-8");
    const duration = Date.now() - startTime;
    console.log(`\u2705 [AutoBackup] \u0627\u0643\u062A\u0645\u0644\u062A \u0627\u0644\u0646\u0633\u062E\u0629 \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A\u0629 \u0641\u064A ${(duration / 1e3).toFixed(1)} \u062B\u0627\u0646\u064A\u0629`);
    console.log(`   \u{1F4CA} ${dumpData.tables.length} \u062C\u062F\u0648\u0644\u060C ${dumpData.totalRows} \u0635\u0641\u060C ${(size / 1024 / 1024).toFixed(2)} MB`);
    return {
      success: true,
      file: backupFile,
      size,
      tablesCount: dumpData.tables.length,
      rowsCount: dumpData.totalRows,
      duration
    };
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : "\u062E\u0637\u0623 \u063A\u064A\u0631 \u0645\u0639\u0631\u0648\u0641";
    console.error("\u274C [AutoBackup] \u0641\u0634\u0644 \u0625\u0646\u0634\u0627\u0621 \u0627\u0644\u0646\u0633\u062E\u0629 \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A\u0629:", errorMsg);
    return {
      success: false,
      file: "",
      size: 0,
      tablesCount: 0,
      rowsCount: 0,
      duration: Date.now() - startTime,
      error: errorMsg
    };
  }
}
function cleanupOldBackups() {
  try {
    const files = readdirSync2(BACKUP_DIR).filter((f) => f.startsWith("full_backup_") && f.endsWith(".json")).map((f) => ({
      name: f,
      path: join4(BACKUP_DIR, f),
      time: statSync2(join4(BACKUP_DIR, f)).mtime.getTime()
    })).sort((a, b) => b.time - a.time);
    if (files.length > MAX_BACKUPS) {
      const toDelete = files.slice(MAX_BACKUPS);
      for (const file of toDelete) {
        unlinkSync3(file.path);
        console.log(`\u{1F5D1}\uFE0F [AutoBackup] \u062A\u0645 \u062D\u0630\u0641 \u0627\u0644\u0646\u0633\u062E\u0629 \u0627\u0644\u0642\u062F\u064A\u0645\u0629: ${file.name}`);
      }
    }
    backupStatus.totalBackups = Math.min(files.length, MAX_BACKUPS);
  } catch (error) {
    console.warn("\u26A0\uFE0F [AutoBackup] \u062E\u0637\u0623 \u0641\u064A \u062A\u0646\u0638\u064A\u0641 \u0627\u0644\u0646\u0633\u062E \u0627\u0644\u0642\u062F\u064A\u0645\u0629:", error);
  }
}
async function runScheduledBackup() {
  if (isBackupRunning) {
    console.log("\u23F3 [AutoBackup] \u0646\u0633\u062E\u0629 \u0627\u062D\u062A\u064A\u0627\u0637\u064A\u0629 \u0642\u064A\u062F \u0627\u0644\u062A\u0646\u0641\u064A\u0630 \u0628\u0627\u0644\u0641\u0639\u0644\u060C \u062A\u062E\u0637\u064A...");
    return;
  }
  isBackupRunning = true;
  backupStatus.isRunning = true;
  try {
    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => reject(new Error("Backup timeout")), BACKUP_TIMEOUT_MS);
    });
    const result = await Promise.race([createFullBackup(), timeoutPromise]);
    if (result.success) {
      backupStatus.lastBackupTime = (/* @__PURE__ */ new Date()).toISOString();
      backupStatus.lastBackupSuccess = true;
      backupStatus.lastBackupFile = result.file;
      backupStatus.lastBackupSize = result.size;
      backupStatus.lastError = null;
      cleanupOldBackups();
    } else {
      backupStatus.lastBackupSuccess = false;
      backupStatus.lastError = result.error || "\u0641\u0634\u0644 \u063A\u064A\u0631 \u0645\u0639\u0631\u0648\u0641";
    }
  } catch (error) {
    const errorMsg = error instanceof Error ? error.message : "\u062E\u0637\u0623 \u063A\u064A\u0631 \u0645\u0639\u0631\u0648\u0641";
    console.error("\u274C [AutoBackup] \u062E\u0637\u0623 \u0641\u064A \u0627\u0644\u0646\u0633\u062E \u0627\u0644\u0645\u062C\u062F\u0648\u0644:", errorMsg);
    backupStatus.lastBackupSuccess = false;
    backupStatus.lastError = errorMsg;
  } finally {
    isBackupRunning = false;
    backupStatus.isRunning = false;
  }
}
function startAutoBackupScheduler() {
  console.log("\u{1F550} [AutoBackup] \u0628\u062F\u0621 \u0646\u0638\u0627\u0645 \u0627\u0644\u0646\u0633\u062E \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A \u0627\u0644\u062A\u0644\u0642\u0627\u0626\u064A...");
  console.log(`   \u23F1\uFE0F \u0627\u0644\u062A\u0643\u0631\u0627\u0631: \u0643\u0644 ${BACKUP_INTERVAL_MS / 6e4} \u062F\u0642\u064A\u0642\u0629`);
  console.log(`   \u{1F4E6} \u0627\u0644\u062D\u062F \u0627\u0644\u0623\u0642\u0635\u0649: ${MAX_BACKUPS} \u0646\u0633\u062E\u0629`);
  initializeBackupDir();
  setTimeout(() => {
    runScheduledBackup();
  }, 1e4);
  schedulerInterval = setInterval(() => {
    runScheduledBackup();
  }, BACKUP_INTERVAL_MS);
  console.log("\u2705 [AutoBackup] \u062A\u0645 \u062A\u0634\u063A\u064A\u0644 \u0646\u0638\u0627\u0645 \u0627\u0644\u0646\u0633\u062E \u0627\u0644\u0627\u062D\u062A\u064A\u0627\u0637\u064A \u0627\u0644\u062A\u0644\u0642\u0627\u0626\u064A");
}
function getAutoBackupStatus() {
  const now = Date.now();
  const lastBackupTime = backupStatus.lastBackupTime ? new Date(backupStatus.lastBackupTime).getTime() : now;
  const timeSinceLastBackup = now - lastBackupTime;
  const nextBackupIn = Math.max(0, BACKUP_INTERVAL_MS - timeSinceLastBackup);
  return {
    ...backupStatus,
    nextBackupIn
  };
}
